module top_module(rev_product, A, B);input [3:0] A, B;
    output [7:0] rev_product;

    integer i;
    reg [7:0] rev_product, temp, B_mod;

    always @ (*) begin
        rev_product = 0;
        B_mod = B;
        for(i=0; i<4; i=i+1) begin
          temp = A[i] ? B_mod : 4'b0000;
          B_mod = B_mod << 1;
          rev_product = rev_product + temp;
        end
    end
endmodule
